from typing import List

class Solution:
    def solve(self, tasks: List[List[int]]) -> int:
        tasks.sort(key=lambda x: x[1])
        prev_end = -1
        max_profit = 0

        for start, end, profit in tasks:
            if start >= prev_end:
                max_profit += profit
                prev_end = end

        return max_profit


if __name__ == '__main__':
    s = Solution()
    tasks = [[1, 2, 3], [2, 4, 2], [1, 3, 1]]
    print(s.solve(tasks))

