from typing import List

class Solution {
public:
    int solve(vector<int>& tasks) {
        sort(tasks.begin(), tasks.end(), [](int a, int b){ return a[1] < b[1]; });
        int prev_end = -1, max_profit = 0;

        for (auto &task : tasks) {
            if (task[0] >= prev_end) {
                max_profit += task[2];
                prev_end = task[1];
            }
        }

        return max_profit;
    }
};

int main()
{
    Solution solution;
    int n;
    cin >> n;
    vector<vector<int>> tasks(n, vector<int>(3));

    for (auto &task : tasks)
    {
        cin >> task[0] >> task[1] >> task[2];
    }

    cout << solution.solve(tasks) << endl;
    return 0;
}
